#define ELF_NGREG 23
typedef unsigned long elf_greg_t;
typedef elf_greg_t elf_gregset_t[ELF_NGREG];
typedef struct user_fpu_struct elf_fpregset_t;

struct user {
	struct {
		unsigned long regs[16];
		unsigned long pc, pr, sr, gbr, mach, macl;
		long tra;
	} regs;
